     1→/**
     2→ * PM Schedule Management Routes
     3→ *
     4→ * REST endpoints for PM schedule CRUD operations and history.
     5→ * Wraps PMSchedulerService with HTTP interface per spec 005.5.
     6→ *
     7→ * Endpoints:
     8→ * - GET /pm/schedule - List schedules with filtering
     9→ * - GET /pm/schedule/:id - Get PM by ID
    10→ * - POST /pm/schedule - Create new PM schedule
    11→ * - PATCH /pm/schedule/:id - Update PM (reschedule, reassign)
    12→ * - POST /pm/schedule/:id/lock - Lock PM to prevent optimizer changes
    13→ * - POST /pm/schedule/:id/unlock - Unlock PM to allow optimizer changes
    14→ * - GET /pm/schedule/:id/history - Get change history
    15→ *
    16→ * @see specs/005-api.md Section 5.5
    17→ */
    18→
    19→import { Hono } from 'hono';
    20→import { eq, and, gte, lte, isNull, count, desc } from 'drizzle-orm';
    21→import type { SQL } from 'drizzle-orm';
    22→import {
    23→  success,
    24→  paginatedSuccess,
    25→  error,
    26→  parsePaginationQuery,
    27→  ErrorCodes,
    28→  type AppVariables,
    29→} from '../types';
    30→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    31→import {
    32→  getPMSchedulerService,
    33→  getManHourLevelingService,
    34→  type SchedulePmRequest,
    35→  type MovePmRequest,
    36→} from '../../services';
    37→import { isValidUuid } from '../../lib/schemas';
    38→import { SYSTEM_USER_ID } from '../../lib/constants';
    39→import { db } from '../../lib/db/connection';
    40→import { pmSchedule } from '../../lib/db/schema';
    41→import { getWebSocketHub } from '../websocket';
    42→
    43→let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
    44→let manHourService: ReturnType<typeof getManHourLevelingService> | null = null;
    45→
    46→function getService(): ReturnType<typeof getPMSchedulerService> {
    47→  if (!pmSchedulerService) {
    48→    pmSchedulerService = getPMSchedulerService();
    49→  }
    50→  return pmSchedulerService;
    51→}
    52→
    53→function getManHourService(): ReturnType<typeof getManHourLevelingService> {
    54→  if (!manHourService) {
    55→    manHourService = getManHourLevelingService();
    56→  }
    57→  return manHourService;
    58→}
    59→
    60→export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    61→
    62→/**
    63→ * GET /pm/schedule
    64→ *
    65→ * List PM schedules with filtering and pagination.
    66→ *
    67→ * Query Parameters:
    68→ * - trainId: Filter by train
    69→ * - depotId: Filter by assigned depot
    70→ * - pmTypeId: Filter by PM type
    71→ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    72→ * - fromDate: Target date from (inclusive)
    73→ * - toDate: Target date to (inclusive)
    74→ * - scenarioId: Get scenario schedule (null/omitted = production)
    75→ */
    76→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    77→  // Parse query filters
    78→  const trainId = c.req.query('trainId');
    79→  const depotId = c.req.query('depotId');
    80→  const pmTypeId = c.req.query('pmTypeId');
    81→  const status = c.req.query('status');
    82→  const fromDate = c.req.query('fromDate');
    83→  const toDate = c.req.query('toDate');
    84→  const scenarioId = c.req.query('scenarioId');
    85→
    86→  // Build filter conditions
    87→  const conditions: SQL<unknown>[] = [];
    88→
    89→  if (trainId && isValidUuid(trainId)) {
    90→    conditions.push(eq(pmSchedule.trainId, trainId));
    91→  }
    92→  if (depotId && isValidUuid(depotId)) {
    93→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
    94→  }
    95→  if (pmTypeId && isValidUuid(pmTypeId)) {
    96→    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
    97→  }
    98→  if (status) {
    99→    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
   100→    if (validStatuses.includes(status as typeof validStatuses[number])) {
   101→      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
   102→    }
   103→  }
   104→  if (fromDate) {
   105→    conditions.push(gte(pmSchedule.targetDate, fromDate));
   106→  }
   107→  if (toDate) {
   108→    conditions.push(lte(pmSchedule.targetDate, toDate));
   109→  }
   110→
   111→  // Handle scenario filter
   112→  if (scenarioId && isValidUuid(scenarioId)) {
   113→    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
   114→  } else {
   115→    // Default to production schedule (scenarioId is NULL)
   116→    conditions.push(isNull(pmSchedule.scenarioId));
   117→  }
   118→
   119→  // Parse pagination
   120→  const pagination = parsePaginationQuery({
   121→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   122→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   123→    sort: c.req.query('sort'),
   124→  });
   125→
   126→  // Count total items
   127→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   128→  const totalResult = await db
   129→    .select({ count: count() })
   130→    .from(pmSchedule)
   131→    .where(whereClause);
   132→  const totalItems = totalResult[0]?.count ?? 0;
   133→
   134→  // Query with relations
   135→  const schedules = await db.query.pmSchedule.findMany({
   136→    where: whereClause,
   137→    with: {
   138→      train: {
   139→        with: {
   140→          fleet: true,
   141→        },
   142→      },
   143→      pmType: true,
   144→      assignedDepot: true,
   145→      assignedTrack: true,
   146→    },
   147→    orderBy: desc(pmSchedule.targetDate),
   148→    limit: pagination.pageSize,
   149→    offset: pagination.offset,
   150→  });
   151→
   152→  // Map to API response format
   153→  const data = schedules.map((pm) => ({
   154→    id: pm.id,
   155→    train: pm.train
   156→      ? {
   157→          id: pm.train.id,
   158→          trainNumber: pm.train.trainNumber,
   159→          fleetCode: pm.train.fleet?.code ?? null,
   160→        }
   161→      : null,
   162→    pmType: pm.pmType
   163→      ? {
   164→          id: pm.pmType.id,
   165→          code: pm.pmType.pmCode,
   166→          name: pm.pmType.pmName,
   167→          estimatedHours: pm.pmType.estimatedHours,
   168→        }
   169→      : null,
   170→    targetDate: pm.targetDate,
   171→    targetMileageKm: pm.targetMileageKm,
   172→    status: pm.status,
   173→    constraintStart: pm.constraintStart,
   174→    constraintEnd: pm.constraintEnd,
   175→    assignedDepot: pm.assignedDepot
   176→      ? {
   177→          id: pm.assignedDepot.id,
   178→          code: pm.assignedDepot.code,
   179→        }
   180→      : null,
   181→    assignedTrack: pm.assignedTrack
   182→      ? {
   183→          id: pm.assignedTrack.id,
   184→          trackNumber: pm.assignedTrack.trackNumber,
   185→          trackType: pm.assignedTrack.trackType,
   186→        }
   187→      : null,
   188→    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   189→    isLocked: pm.isLocked ?? false,
   190→    maximoWoId: pm.maximoWoId,
   191→  }));
   192→
   193→  return c.json(
   194→    paginatedSuccess(
   195→      data,
   196→      {
   197→        page: pagination.page,
   198→        pageSize: pagination.pageSize,
   199→        totalItems,
   200→      },
   201→      { durationMs: getRequestDuration(c) }
   202→    )
   203→  );
   204→});
   205→
   206→/**
   207→ * GET /pm/schedule/:id
   208→ *
   209→ * Get PM schedule details by ID.
   210→ */
   211→pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
   212→  const requestId = getRequestId(c);
   213→  const pmId = c.req.param('id');
   214→
   215→  if (!isValidUuid(pmId)) {
   216→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   217→  }
   218→
   219→  const service = getService();
   220→  const pmResult = await service.getPm(pmId);
   221→
   222→  // Cast to include all query relations (service returns more than type declares)
   223→  const pm = pmResult as typeof pmResult & {
   224→    assignedDepot: { id: string; code: string; name: string } | null;
   225→  };
   226→
   227→  // Check material availability for upcoming PMs
   228→  let materialStatus = { allAvailable: true, warnings: [] as string[] };
   229→  if (pm.status === 'SCHEDULED' && pm.assignedDepotId) {
   230→    try {
   231→      const materialResult = await service.checkMaterialAvailability(
   232→        pm.pmTypeId,
   233→        pm.assignedDepotId,
   234→        pm.targetDate
   235→      );
   236→      materialStatus = {
   237→        allAvailable: !materialResult.isBlocked && materialResult.softConstraintWarnings.length === 0,
   238→        warnings: [
   239→          ...materialResult.hardConstraintViolations.map((v) => `Blocked: ${v.partNumber} (need ${v.requiredQuantity}, have ${v.availableQuantity})`),
   240→          ...materialResult.softConstraintWarnings.map((v) => `Warning: ${v.partNumber} may not be available`),
   241→        ],
   242→      };
   243→    } catch {
   244→      // Material check failed, assume available
   245→    }
   246→  }
   247→
   248→  return c.json(
   249→    success({
   250→      id: pm.id,
   251→      train: pm.train
   252→        ? {
   253→            id: pm.train.id,
   254→            trainNumber: pm.train.trainNumber,
   255→            fleetId: pm.train.fleetId,
   256→          }
   257→        : null,
   258→      pmType: pm.pmType
   259→        ? {
   260→            id: pm.pmType.id,
   261→            code: pm.pmType.pmCode,
   262→            name: pm.pmType.pmName,
   263→            estimatedHours: pm.pmType.estimatedHours,
   264→          }
   265→        : null,
   266→      targetDate: pm.targetDate,
   267→      targetMileageKm: pm.targetMileageKm,
   268→      status: pm.status,
   269→      constraintStart: pm.constraintStart,
   270→      constraintEnd: pm.constraintEnd,
   271→      assignedDepot: pm.assignedDepot
   272→        ? {
   273→            id: pm.assignedDepot.id,
   274→            code: pm.assignedDepot.code,
   275→            name: pm.assignedDepot.name,
   276→          }
   277→        : null,
   278→      assignedTrack: pm.assignedTrack
   279→        ? {
   280→            id: pm.assignedTrack.id,
   281→            trackNumber: pm.assignedTrack.trackNumber,
   282→            trackType: pm.assignedTrack.trackType,
   283→          }
   284→        : null,
   285→      assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   286→      assignedShift: pm.assignedShift,
   287→      isLocked: pm.isLocked ?? false,
   288→      lockedReason: pm.lockedReason,
   289→      maximoWoId: pm.maximoWoId,
   290→      materialStatus,
   291→      actualStartDate: pm.actualStartDate,
   292→      actualEndDate: pm.actualEndDate,
   293→      actualHours: pm.actualHours ? Number(pm.actualHours) : null,
   294→      completedAt: pm.completedAt,
   295→      completedMileageKm: pm.completedMileageKm,
   296→      createdAt: pm.createdAt,
   297→      updatedAt: pm.updatedAt,
   298→    })
   299→  );
   300→});
   301→
   302→/**
   303→ * POST /pm/schedule
   304→ *
   305→ * Create a new PM schedule entry.
   306→ *
   307→ * Request body:
   308→ * - trainId: UUID of train
   309→ * - pmTypeId: UUID of PM type
   310→ * - targetDate: Target date (YYYY-MM-DD)
   311→ * - assignedDepotId?: UUID of assigned depot
   312→ * - assignedTrackId?: UUID of assigned track
   313→ * - scenarioId?: UUID of scenario (null for production)
   314→ * - reason?: Reason for manual scheduling
   315→ */
   316→pmScheduleRoutes.post('/pm/schedule', async (c) => {
   317→  const requestId = getRequestId(c);
   318→  const body = await c.req.json();
   319→
   320→  // Validate required fields
   321→  if (!body.trainId || !isValidUuid(body.trainId)) {
   322→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'trainId is required and must be a valid UUID', requestId), 400);
   323→  }
   324→  if (!body.pmTypeId || !isValidUuid(body.pmTypeId)) {
   325→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'pmTypeId is required and must be a valid UUID', requestId), 400);
   326→  }
   327→  if (!body.targetDate || !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   328→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required and must be in YYYY-MM-DD format', requestId), 400);
   329→  }
   330→
   331→  // Validate optional UUIDs
   332→  if (body.assignedDepotId && !isValidUuid(body.assignedDepotId)) {
   333→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedDepotId must be a valid UUID', requestId), 400);
   334→  }
   335→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   336→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   337→  }
   338→
   339→  const service = getService();
   340→  const user = c.get('user');
   341→
   342→  const request: SchedulePmRequest = {
   343→    trainId: body.trainId,
   344→    pmTypeId: body.pmTypeId,
   345→    targetDate: body.targetDate,
   346→    assignedDepotId: body.assignedDepotId,
   347→    assignedTrackId: body.assignedTrackId,
   348→    assignedShift: body.assignedShift,
   349→    notes: body.reason,
   350→    createdBy: user?.id,
   351→  };
   352→
   353→  const created = await service.schedulePm(request);
   354→
   355→  return c.json(
   356→    success({
   357→      id: created.id,
   358→      trainId: created.trainId,
   359→      pmTypeId: created.pmTypeId,
   360→      targetDate: created.targetDate,
   361→      targetMileageKm: created.targetMileageKm,
   362→      status: created.status,
   363→      constraintStart: created.constraintStart,
   364→      constraintEnd: created.constraintEnd,
   365→      assignedDepotId: created.assignedDepotId,
   366→      assignedTrackId: created.assignedTrackId,
   367→      assignedHours: created.assignedHours ? Number(created.assignedHours) : null,
   368→      createdAt: created.createdAt,
   369→    }),
   370→    201
   371→  );
   372→});
   373→
   374→/**
   375→ * PATCH /pm/schedule/:id
   376→ *
   377→ * Update a PM schedule entry (move, reassign).
   378→ *
   379→ * Request body:
   380→ * - targetDate?: New target date
   381→ * - assignedTrackId?: New track assignment
   382→ * - reason: Reason for change (required)
   383→ */
   384→pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   385→  const requestId = getRequestId(c);
   386→  const pmId = c.req.param('id');
   387→
   388→  if (!isValidUuid(pmId)) {
   389→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   390→  }
   391→
   392→  const body = await c.req.json();
   393→
   394→  // Validate reason is provided
   395→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   396→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   397→  }
   398→
   399→  // Validate targetDate if provided
   400→  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   401→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   402→  }
   403→
   404→  // Validate assignedTrackId if provided
   405→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   406→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   407→  }
   408→
   409→  const service = getService();
   410→  const user = c.get('user');
   411→
   412→  // Get current PM to capture old values
   413→  const currentPm = await service.getPm(pmId);
   414→
   415→  // Only proceed if targetDate is being changed
   416→  if (!body.targetDate) {
   417→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate is required for PM move', requestId), 400);
   418→  }
   419→
   420→  const request: MovePmRequest = {
   421→    pmScheduleId: pmId,
   422→    newTargetDate: body.targetDate,
   423→    newTrackId: body.assignedTrackId,
   424→    reason: body.reason,
   425→    movedBy: user?.id ?? SYSTEM_USER_ID,
   426→  };
   427→
   428→  const updated = await service.movePm(request);
   429→
   430→  // Calculate impact assessment
   431→  let manhourImpact = 0;
   432→  let conflictsCreated = 0;
   433→
   434→  // Calculate man-hour impact if depot is assigned
   435→  const depotId = updated.assignedDepotId ?? currentPm.assignedDepotId;
   436→  if (depotId) {
   437→    const estimatedHours = parseFloat(currentPm.pmType?.estimatedHours ?? '0');
   438→    const manHourSvc = getManHourService();
   439→
   440→    // Get old and new week utilization
   441→    // When PM moves, it removes hours from old week and adds to new week
   442→    const [oldWeekCapacity, newWeekCapacity] = await Promise.all([
   443→      manHourSvc.checkLaborCapacity(depotId, currentPm.targetDate, 0),
   444→      manHourSvc.checkLaborCapacity(depotId, updated.targetDate, estimatedHours),
   445→    ]);
   446→
   447→    // Impact is the change in new week's utilization
   448→    // Positive = increased load, Negative = decreased load
   449→    manhourImpact = Math.round(
   450→      (newWeekCapacity.utilizationPct - oldWeekCapacity.utilizationPct) * 100
   451→    ) / 100;
   452→  }
   453→
   454→  // Conflicts check: movePm already validates and throws on track conflicts
   455→  // If we reach here, no new conflicts were created
   456→  // The value 0 is correct - if there were conflicts, movePm would have thrown
   457→  conflictsCreated = 0;
   458→
   459→  const impactAssessment = {
   460→    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
   461→      ? 'WITHIN_WINDOW'
   462→      : 'OUTSIDE_WINDOW',
   463→    manhourImpact,
   464→    conflictsCreated,
   465→  };
   466→
   467→  // Broadcast PM update to all connected canvas subscribers
   468→  const hub = getWebSocketHub();
   469→  hub.broadcastPmUpdated({
   470→    pmId: updated.id,
   471→    trainId: updated.trainId,
   472→    trainNumber: currentPm.train?.trainNumber ?? 'Unknown',
   473→    changes: [
   474→      { field: 'targetDate', oldValue: currentPm.targetDate, newValue: updated.targetDate },
   475→      ...(body.assignedTrackId && body.assignedTrackId !== currentPm.assignedTrackId
   476→        ? [{ field: 'assignedTrackId', oldValue: currentPm.assignedTrackId, newValue: body.assignedTrackId }]
   477→        : []),
   478→    ],
   479→    changedBy: {
   480→      userId: user?.id ?? SYSTEM_USER_ID,
   481→      displayName: user?.email ?? 'System',
   482→    },
   483→  });
   484→
   485→  return c.json(
   486→    success({
   487→      id: updated.id,
   488→      targetDate: updated.targetDate,
   489→      previousTargetDate: currentPm.targetDate,
   490→      assignedTrackId: updated.assignedTrackId,
   491→      previousTrackId: currentPm.assignedTrackId,
   492→      updatedAt: updated.updatedAt,
   493→      updatedBy: user?.id,
   494→      explanation: {
   495→        changeType: 'DATE_CHANGED',
   496→        reason: body.reason,
   497→        impactAssessment,
   498→      },
   499→    })
   500→  );
   501→});
   502→
   503→/**
   504→ * POST /pm/schedule/:id/lock
   505→ *
   506→ * Lock a PM to prevent optimizer changes.
   507→ *
   508→ * Request body:
   509→ * - reason: Reason for locking (required)
   510→ */
   511→pmScheduleRoutes.post('/pm/schedule/:id/lock', async (c) => {
   512→  const requestId = getRequestId(c);
   513→  const pmId = c.req.param('id');
   514→
   515→  if (!isValidUuid(pmId)) {
   516→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   517→  }
   518→
   519→  const body = await c.req.json();
   520→
   521→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   522→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for locking', requestId), 400);
   523→  }
   524→
   525→  const service = getService();
   526→  const user = c.get('user');
   527→
   528→  // Get PM with train details for broadcast
   529→  const pm = await service.getPm(pmId);
   530→
   531→  const updated = await service.lockPm(pmId, body.reason, user?.id ?? SYSTEM_USER_ID);
   532→
   533→  // Broadcast lock event to all connected canvas subscribers
   534→  const hub = getWebSocketHub();
   535→  hub.broadcastPmLocked({
   536→    pmId: updated.id,
   537→    trainId: pm.trainId,
   538→    trainNumber: pm.train?.trainNumber ?? 'Unknown',
   539→    isLocked: true,
   540→    lockedReason: body.reason,
   541→    lockedBy: {
   542→      userId: user?.id ?? SYSTEM_USER_ID,
   543→      displayName: user?.email ?? 'System',
   544→    },
   545→  });
   546→
   547→  return c.json(
   548→    success({
   549→      id: updated.id,
   550→      isLocked: updated.isLocked,
   551→      lockedReason: updated.lockedReason,
   552→      lockedBy: updated.lockedBy,
   553→      lockedAt: updated.lockedAt,
   554→    })
   555→  );
   556→});
   557→
   558→/**
   559→ * POST /pm/schedule/:id/unlock
   560→ *
   561→ * Unlock a PM to allow optimizer changes.
   562→ */
   563→pmScheduleRoutes.post('/pm/schedule/:id/unlock', async (c) => {
   564→  const requestId = getRequestId(c);
   565→  const pmId = c.req.param('id');
   566→
   567→  if (!isValidUuid(pmId)) {
   568→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   569→  }
   570→
   571→  const service = getService();
   572→  const user = c.get('user');
   573→
   574→  // Get PM with train details for broadcast
   575→  const pm = await service.getPm(pmId);
   576→
   577→  const updated = await service.unlockPm(pmId, user?.id ?? SYSTEM_USER_ID);
   578→
