   210→  horizonEnd: string;
   211→  scheduled: SchedulingResultItem[];
   212→  deferred: SchedulingResultItem[];
   213→  blocked: SchedulingResultItem[];
   214→  materialWarnings: Array<{
   215→    trainId: string;
   216→    trainNumber: string;
