   228→}
   229→
   230→/** Request to schedule a PM */
   231→export interface SchedulePmRequest {
   232→  trainId: string;
   233→  pmTypeId: string;
   234→  targetDate: string;
   235→  assignedDepotId?: string;
   236→  assignedTrackId?: string;
   237→  assignedShift?: 'DAY' | 'NIGHT' | 'WEEKEND' | 'HOLIDAY';
   238→  notes?: string;
   239→  createdBy?: string;
   240→  skipMaterialCheck?: boolean;
   241→  skipServiceDemandCheck?: boolean;
   242→  skipLaborCapacityCheck?: boolean;
   243→}
   244→
   245→/** Request to move a PM */
   246→export interface MovePmRequest {
   247→  pmScheduleId: string;
   248→  newTargetDate: string;
   249→  newTrackId?: string;
   250→  reason: string;
   251→  movedBy: string;
   252→}
   253→
   254→/** Request to run tactical scheduling */
   255→export interface TacticalScheduleRequest {
   256→  fleetId?: string;
   257→  depotId?: string;
