   990→  async schedulePm(request: SchedulePmRequest): Promise<PmScheduleRecord> {
   991→    return this.inTransaction('schedulePm', async (tx, span) => {
   992→      const {
   993→        trainId,
   994→        pmTypeId,
   995→        targetDate,
   996→        assignedDepotId,
   997→        assignedTrackId,
   998→        assignedShift,
   999→        notes,
