  1265→  /**
  1266→   * Move an existing PM to a new date.
  1267→   */
  1268→  async movePm(request: MovePmRequest): Promise<PmScheduleRecord> {
  1269→    return this.inTransaction('movePm', async (tx, span) => {
  1270→      const { pmScheduleId, newTargetDate, newTrackId, reason, movedBy } = request;
  1271→
  1272→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1273→      span.setAttribute('pm.newTargetDate', newTargetDate);
  1274→
  1275→      // Get existing PM with relations
  1276→      const existingPm = await tx.query.pmSchedule.findFirst({
  1277→        where: eq(pmSchedule.id, pmScheduleId),
  1278→        with: {
  1279→          train: true,
  1280→          pmType: true,
  1281→          assignedTrack: true,
  1282→        },
  1283→      }) as PmWithDetails | null;
  1284→
  1285→      if (!existingPm) {
  1286→        throw new PmScheduleNotFoundError(pmScheduleId);
  1287→      }
  1288→
  1289→      // Check Maximo lock
  1290→      const lockStatus = await this.checkMaximoLock(pmScheduleId);
  1291→      if (lockStatus.isLocked) {
  1292→        throw new MaximoLockError(
  1293→          `PM cannot be moved: ${lockStatus.reason}`,
  1294→          {
  1295→            workOrderId: lockStatus.workOrderId ?? undefined,
  1296→            maximoStatus: lockStatus.maximoStatus ?? undefined,
  1297→          }
  1298→        );
  1299→      }
  1300→
  1301→      // Check status - only SCHEDULED can be moved
  1302→      if (existingPm.status !== 'SCHEDULED') {
  1303→        throw new BusinessRuleError(
  1304→          `PM cannot be moved: status is ${existingPm.status}`,
  1305→          {
  1306→            rule: 'pm_status_move',
  1307→            context: { currentStatus: existingPm.status },
  1308→          }
  1309→        );
  1310→      }
  1311→
  1312→      // Validate new date is within compliance window
  1313→      if (newTargetDate < existingPm.constraintStart ||
  1314→          newTargetDate > existingPm.constraintEnd) {
  1315→        throw new ComplianceWindowError(
  1316→          `New target date ${newTargetDate} is outside compliance window [${existingPm.constraintStart}, ${existingPm.constraintEnd}]`,
  1317→          {
  1318→            windowStart: new Date(existingPm.constraintStart),
  1319→            windowEnd: new Date(existingPm.constraintEnd),
  1320→            targetDate: new Date(newTargetDate),
  1321→          }
  1322→        );
  1323→      }
  1324→
  1325→      // Check service demand at new date
  1326→      const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1327→        existingPm.trainId,
  1328→        newTargetDate
  1329→      );
  1330→
  1331→      if (!canSchedule) {
  1332→        throw new ServiceDemandViolationError(
  1333→          validation.message,
  1334→          {
  1335→            fleetId: validation.fleetId,
  1336→            requiredTrains: validation.required,
  1337→            availableTrains: validation.availableTrains,
  1338→          }
  1339→        );
  1340→      }
  1341→
  1342→      // Handle track change
  1343→      let trackId = newTrackId ?? existingPm.assignedTrackId;
  1344→      if (trackId) {
  1345→        const conflict = await this.checkTrackConflict(
  1346→          trackId,
  1347→          newTargetDate,
  1348→          existingPm.pmType?.minTrackDays ?? 1,
  1349→          pmScheduleId
  1350→        );
  1351→
  1352→        if (conflict) {
  1353→          // Try to find alternative track
  1354→          if (!newTrackId) {
  1355→            const alternatives = await this.findSuitableTracks(
  1356→              existingPm.pmTypeId,
  1357→              existingPm.assignedDepotId,
  1358→              newTargetDate,
  1359→              existingPm.pmType?.minTrackDays ?? 1
  1360→            );
  1361→
  1362→            if (alternatives.length > 0) {
  1363→              trackId = alternatives[0].trackId;
  1364→            } else {
  1365→              trackId = null; // Clear track assignment
  1366→            }
  1367→          } else {
  1368→            throw new TrackConflictError(
  1369→              `Track is already occupied on ${newTargetDate}`,
  1370→              {
  1371→                trackId,
  1372→                conflictingScheduleId: conflict.id,
  1373→              }
  1374→            );
  1375→          }
  1376→        }
  1377→      }
  1378→
  1379→      // Calculate new target mileage
  1380→      const dailyKm = await this.getAverageDailyKm(existingPm.trainId);
  1381→      const today = new Date();
  1382→      const daysUntilTarget = Math.ceil(
  1383→        (new Date(newTargetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
  1384→      );
  1385→      const currentMileage = existingPm.train?.currentMileageKm ?? 0;
  1386→      const newTargetMileageKm = currentMileage + (daysUntilTarget * dailyKm);
  1387→
  1388→      // Record old values for history
  1389→      const oldTargetDate = existingPm.targetDate;
  1390→      const oldTrackId = existingPm.assignedTrackId;
  1391→
  1392→      // Update PM schedule
  1393→      const [updated] = await tx
  1394→        .update(pmSchedule)
  1395→        .set({
  1396→          targetDate: newTargetDate,
  1397→          targetMileageKm: Math.round(newTargetMileageKm),
  1398→          assignedTrackId: trackId,
  1399→          updatedAt: new Date(),
  1400→        })
  1401→        .where(eq(pmSchedule.id, pmScheduleId))
  1402→        .returning();
  1403→
  1404→      // Create audit history record
  1405→      const historyRecord: NewPmScheduleHistory = {
  1406→        pmScheduleId,
  1407→        changeType: 'DATE_CHANGED',
  1408→        oldTargetDate,
  1409→        newTargetDate,
  1410→        oldAssignedTrackId: oldTrackId,
  1411→        newAssignedTrackId: trackId,
  1412→        changedBy: movedBy,
  1413→        changeReason: reason,
  1414→        changeSource: 'USER',
  1415→      };
  1416→
  1417→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1418→
  1419→      const trainNumber = existingPm.train?.trainNumber ?? 'unknown';
  1420→      const pmCode = existingPm.pmType?.pmCode ?? 'unknown';
  1421→
  1422→      this.log.info(
  1423→        {
  1424→          pmScheduleId,
  1425→          trainNumber,
  1426→          pmCode,
  1427→          oldTargetDate,
  1428→          newTargetDate,
  1429→          reason,
  1430→          movedBy,
  1431→        },
  1432→        `PM moved: ${pmCode} for ${trainNumber} from ${oldTargetDate} to ${newTargetDate}`
  1433→      );
  1434→
  1435→      return updated;
  1436→    });
  1437→  }
