  2158→  /**
  2159→   * Calculate track utilization percentage for a period.
  2160→   */
  2161→  private async calculateTrackUtilization(
  2162→    startDate: string,
  2163→    endDate: string,
  2164→    depotId: string | null
  2165→  ): Promise<number> {
  2166→    // Get total track-days available
  2167→    const trackConditions: SQL<unknown>[] = [
  2168→      eq(tracks.active, true),
  2169→      sql`${tracks.trackType} != 'STABLING'`,
  2170→    ];
  2171→
  2172→    if (depotId) {
  2173→      trackConditions.push(eq(tracks.depotId, depotId));
  2174→    }
  2175→
  2176→    const trackCount = await this.db
  2177→      .select({ count: count() })
  2178→      .from(tracks)
  2179→      .where(and(...trackConditions));
  2180→
  2181→    const totalTracks = trackCount[0]?.count ?? 0;
  2182→    const daysBetween = Math.ceil(
  2183→      (new Date(endDate).getTime() - new Date(startDate).getTime()) / (1000 * 60 * 60 * 24)
  2184→    );
  2185→    const totalTrackDays = totalTracks * daysBetween;
  2186→
  2187→    if (totalTrackDays === 0) return 0;
  2188→
  2189→    // Get scheduled PM track-days
  2190→    const pmConditions: SQL<unknown>[] = [
  2191→      inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  2192→      isNull(pmSchedule.scenarioId),
  2193→      gte(pmSchedule.targetDate, startDate),
  2194→      lte(pmSchedule.targetDate, endDate),
  2195→      sql`${pmSchedule.assignedTrackId} IS NOT NULL`,
  2196→    ];
  2197→
  2198→    if (depotId) {
  2199→      pmConditions.push(eq(pmSchedule.assignedDepotId, depotId));
  2200→    }
  2201→
  2202→    const scheduledPms = await this.db.query.pmSchedule.findMany({
  2203→      where: and(...pmConditions),
  2204→      with: { pmType: true },
  2205→    });
  2206→
  2207→    const usedTrackDays = scheduledPms.reduce((sum, pm) => {
  2208→      const duration = pm.pmType?.minTrackDays ?? 1;
  2209→      return sum + duration;
  2210→    }, 0);
  2211→
  2212→    return Math.round((usedTrackDays / totalTrackDays) * 100);
  2213→  }
  2214→}
