/**
 * MMS PM Scheduler Service - Tactical PM Scheduling
 *
 * Schedules preventive maintenance within a 12-week horizon, respecting:
 * - Compliance windows (mileage OR time triggers)
 * - PM hierarchy (C4 satisfies C1/C2/C3)
 * - Track capability requirements
 * - Material constraints (hard 14 days, soft 90 days)
 * - Labor capacity (depot man-hour availability)
 * - Maximo lock status (INPRG work orders are read-only)
 * - Service demand (fleet availability)
 *
 * Key business rules:
 * - Compliance window: ±10% of interval (mileage or months)
 * - PM hierarchy: Higher-level PMs satisfy lower-level requirements
 * - Material hard constraint: BLOCKING parts must be available within 14 days
 * - Material soft constraint: Warning if parts unavailable within 90 days
 * - Labor capacity: PM hours must fit within weekly depot capacity
 * - Track utilization target: 85%
 * - Maximo lock: Cannot modify PM with INPRG work order
 *
 * @see specs/003-database-schema.md Section 3.5 (PM Management)
 * @see specs/004-domain-services.md Section 4.4 (PM Scheduler)
 */

import { eq, and, sql, desc, inArray, gte, lte, isNull, count } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  pmSchedule,
  pmTypes,
  pmMaterialRequirements,
  trains,
  tracks,
  trackCapabilities,
  pmCapabilityRequirements,
  inventoryPositions,
  materialReservations,
  pmScheduleHistory,
  mileageReadings,
  type PmScheduleRecord,
  type NewPmScheduleRecord,
  type PmType,
  type Train,
  type Track,
  type NewPmScheduleHistory,
} from '../lib/db/schema';
import {
  NotFoundError,
  PmScheduleNotFoundError,
  TrainNotFoundError,
  MaximoLockError,
  ComplianceWindowError,
  TrackConflictError,
  MaterialConstraintError,
  ServiceDemandViolationError,
  LaborCapacityError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';
import { getServiceDemandService } from './service-demand';
import { getUnavailabilityService } from './unavailability';
import { getManHourLevelingService, type LaborCapacityResult } from './man-hour-leveling';

// =============================================================================
// Types
// =============================================================================

/** Track type values */
type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';

/** Material criticality values */
type MaterialCriticality = 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';

/** Reservation type values */
type ReservationType = 'SOFT' | 'HARD';

/** PM due calculation result */
export interface PmDueResult {
  pmTypeId: string;
  pmCode: string;
  pmName: string;
  trainId: string;
  trainNumber: string;
  fleetId: string;
  dueMileageKm: number | null;
  dueDate: string | null;
  currentMileageKm: number;
  kmUntilDue: number | null;
  daysUntilDue: number | null;
  triggerType: 'MILEAGE' | 'TIME' | 'BOTH';
  complianceWindow: ComplianceWindow;
  isOverdue: boolean;
  lastPmDate: string | null;
  lastPmMileageKm: number | null;
}

/** Compliance window for scheduling */
export interface ComplianceWindow {
  startDate: string;
  endDate: string;
  startMileageKm: number | null;
  endMileageKm: number | null;
  idealDate: string;
  idealMileageKm: number | null;
}

/** Material availability check result */
export interface MaterialAvailability {
  partNumber: string;
  partDescription: string | null;
  criticality: MaterialCriticality;
  requiredQuantity: number;
  availableQuantity: number;
  depotId: string;
  isAvailable: boolean;
  shortfall: number;
  leadTimeDays: number;
  expectedAvailableDate: string | null;
}

/** Material constraint check result */
export interface MaterialConstraintResult {
  isBlocked: boolean;
  hardConstraintViolations: MaterialAvailability[];
  softConstraintWarnings: MaterialAvailability[];
  totalMissingParts: number;
  reservations: Array<{
    partNumber: string;
    quantity: number;
    type: ReservationType;
  }>;
}

/** Track allocation result */
export interface TrackAllocation {
  trackId: string;
  trackNumber: string;
  depotId: string;
  depotCode: string;
  trackType: TrackType;
  startDate: string;
  endDate: string;
  hasAllCapabilities: boolean;
  missingCapabilities: string[];
}

/** Scheduling result for a single PM */
export interface SchedulingResultItem {
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  status: 'SCHEDULED' | 'DEFERRED' | 'BLOCKED';
  targetDate: string | null;
  targetMileageKm: number | null;
  trackAllocation: TrackAllocation | null;
  materialConstraint: MaterialConstraintResult | null;
  laborCapacity: LaborCapacityResult | null;
  complianceWindow: ComplianceWindow;
  deferralReason: string | null;
  warnings: string[];
  explanation: SchedulingExplanation;
}

/** Explanation trace for scheduling decisions */
export interface SchedulingExplanation {
  mileageTrigger: {
    intervalKm: number | null;
    currentMileageKm: number;
    lastPmMileageKm: number | null;
    kmSinceLastPm: number | null;
    kmUntilDue: number | null;
  };
  timeTrigger: {
    intervalMonths: number | null;
    lastPmDate: string | null;
    daysSinceLastPm: number | null;
    daysUntilDue: number | null;
  };
  hierarchySatisfied: {
    satisfiedBy: string | null;
    satisfiedOnDate: string | null;
    counterResetFrom: number | null;
  };
  trackSelection: {
    candidateTracks: number;
    selectedTrackId: string | null;
    selectionReason: string;
  };
  materialCheck: {
    totalParts: number;
    availableParts: number;
    blockedParts: number;
    warningParts: number;
  };
  laborCapacityCheck: {
    estimatedHours: number;
    weeklyCapacity: number;
    currentUtilization: number;
    utilizationAfterScheduling: number;
    hasCapacity: boolean;
  };
  constraints: string[];
}

/** Full scheduling result */
export interface SchedulingResult {
  horizonStart: string;
  horizonEnd: string;
  scheduled: SchedulingResultItem[];
  deferred: SchedulingResultItem[];
  blocked: SchedulingResultItem[];
  materialWarnings: Array<{
    trainId: string;
    trainNumber: string;
    pmCode: string;
    targetDate: string;
    warnings: MaterialAvailability[];
  }>;
  summary: {
    totalProcessed: number;
    totalScheduled: number;
    totalDeferred: number;
    totalBlocked: number;
    trackUtilizationPct: number;
  };
}

/** Request to schedule a PM */
export interface SchedulePmRequest {
  trainId: string;
  pmTypeId: string;
  targetDate: string;
  assignedDepotId?: string;
  assignedTrackId?: string;
  assignedShift?: 'DAY' | 'NIGHT' | 'WEEKEND' | 'HOLIDAY';
  notes?: string;
  createdBy?: string;
  skipMaterialCheck?: boolean;
  skipServiceDemandCheck?: boolean;
  skipLaborCapacityCheck?: boolean;
}

/** Request to move a PM */
export interface MovePmRequest {
  pmScheduleId: string;
  newTargetDate: string;
  newTrackId?: string;
  reason: string;
  movedBy: string;
}

/** Request to run tactical scheduling */
export interface TacticalScheduleRequest {
  fleetId?: string;
  depotId?: string;
  horizonWeeks?: number;
  dryRun?: boolean;
  respectLocks?: boolean;
}

/** PM with details for scheduling */
interface PmWithDetails extends PmScheduleRecord {
  train: Train | null;
  pmType: PmType | null;
  assignedTrack: Track | null;
}

// =============================================================================
// Constants
// =============================================================================

/** Default horizon for tactical scheduling (weeks) */
const DEFAULT_HORIZON_WEEKS = 12;

/** Hard material constraint window (days before PM) */
const HARD_MATERIAL_WINDOW_DAYS = 14;

/** Soft material constraint window (days before PM) */
const SOFT_MATERIAL_WINDOW_DAYS = 90;

/** Default daily mileage rate for projections (km) */
const DEFAULT_DAILY_KM = 250;

/** Default compliance tolerance percentage */
const DEFAULT_TOLERANCE_PCT = 10;

// =============================================================================
// PM Scheduler Service
// =============================================================================

export class PMSchedulerService extends BaseService {
  private serviceDemandService = getServiceDemandService();
  private unavailabilityService = getUnavailabilityService();
  private manHourLevelingService = getManHourLevelingService();

  constructor() {
    super({ name: 'pm-scheduler-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Compliance Window Calculation
  // ===========================================================================

  /**
   * Calculate compliance window for a PM type and train.
   *
   * The compliance window defines the valid date range for scheduling a PM.
   * It is calculated based on:
   * - Mileage trigger: intervalKm ± tolerance%
   * - Time trigger: intervalMonths ± tolerance%
   * - Whichever comes first determines the due date
   *
   * @param trainId - Train to calculate for
   * @param pmTypeId - PM type to calculate for
   * @returns Compliance window with start/end dates and mileage
   */
  async calculateComplianceWindow(
    trainId: string,
    pmTypeId: string
  ): Promise<PmDueResult> {
    return this.traced('calculateComplianceWindow', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('pm.typeId', pmTypeId);

      // Get train details
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
        with: { fleet: true },
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);
      span.setAttribute(MmsAttributes.FLEET_ID, train.fleetId);

      // Get PM type details
      const pmType = await this.db.query.pmTypes.findFirst({
        where: and(
          eq(pmTypes.id, pmTypeId),
          eq(pmTypes.active, true)
        ),
      });

      if (!pmType) {
        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
          entityType: 'pm_type',
          entityId: pmTypeId,
        });
      }

      // Get last completed PM of this type for this train
      const lastPm = await this.getLastCompletedPm(trainId, pmTypeId);

      // Check if a higher-level PM has satisfied this requirement
      const hierarchySatisfied = await this.checkHierarchySatisfaction(
        trainId,
        pmType,
        lastPm?.completedAt ?? null
      );

      // Use hierarchy satisfaction if more recent
      const effectiveLastPm = hierarchySatisfied?.satisfiedByPm &&
        (!lastPm || new Date(hierarchySatisfied.satisfiedByPm.completedAt ?? 0) > new Date(lastPm.completedAt ?? 0))
        ? hierarchySatisfied.satisfiedByPm
        : lastPm;

      const lastPmDate = effectiveLastPm?.completedAt
        ? new Date(effectiveLastPm.completedAt).toISOString().split('T')[0]
        : train.commissioningDate ?? null;
      const lastPmMileageKm = effectiveLastPm?.completedMileageKm ?? 0;

      // Calculate due date and mileage
      const currentMileageKm = train.currentMileageKm ?? 0;
      const today = new Date();
      const todayStr = today.toISOString().split('T')[0];

      // Get early/late tolerance
      const earlyTolerancePct = Number(pmType.earlyTolerancePct) || DEFAULT_TOLERANCE_PCT;
      const lateTolerancePct = Number(pmType.lateTolerancePct) || DEFAULT_TOLERANCE_PCT;

      // Calculate mileage trigger
      let dueMileageKm: number | null = null;
      let kmUntilDue: number | null = null;
      let mileageWindowStart: number | null = null;
      let mileageWindowEnd: number | null = null;

      if (pmType.intervalKm) {
        dueMileageKm = lastPmMileageKm + pmType.intervalKm;
        kmUntilDue = dueMileageKm - currentMileageKm;

        const toleranceKm = pmType.intervalKm * (earlyTolerancePct / 100);
        mileageWindowStart = dueMileageKm - toleranceKm;
        mileageWindowEnd = dueMileageKm + (pmType.intervalKm * (lateTolerancePct / 100));
      }

      // Calculate time trigger
      let dueDate: string | null = null;
      let daysUntilDue: number | null = null;
      let dateWindowStart: string | null = null;
      let dateWindowEnd: string | null = null;

      if (pmType.intervalMonths && lastPmDate) {
        const lastDate = new Date(lastPmDate);
        const dueDateTime = new Date(lastDate);
        dueDateTime.setMonth(dueDateTime.getMonth() + pmType.intervalMonths);
        dueDate = dueDateTime.toISOString().split('T')[0];
        daysUntilDue = Math.ceil((dueDateTime.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

        const toleranceDays = Math.round((pmType.intervalMonths * 30) * (earlyTolerancePct / 100));
        const lateDays = Math.round((pmType.intervalMonths * 30) * (lateTolerancePct / 100));

        const windowStartDate = new Date(dueDateTime);
        windowStartDate.setDate(windowStartDate.getDate() - toleranceDays);
        dateWindowStart = windowStartDate.toISOString().split('T')[0];

        const windowEndDate = new Date(dueDateTime);
        windowEndDate.setDate(windowEndDate.getDate() + lateDays);
        dateWindowEnd = windowEndDate.toISOString().split('T')[0];
      }

      // Determine trigger type (which comes first)
      let triggerType: 'MILEAGE' | 'TIME' | 'BOTH' = 'BOTH';
      let idealDate = todayStr;
      let idealMileageKm = currentMileageKm;

      if (dueMileageKm !== null && dueDate !== null) {
        // Convert mileage due to date using daily rate
        const dailyKm = await this.getAverageDailyKm(trainId);
        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
        const mileageDueDate = new Date(mileageDueDateMs);

        const timeDueDate = new Date(dueDate);

        if (mileageDueDate < timeDueDate) {
          triggerType = 'MILEAGE';
          idealDate = mileageDueDate.toISOString().split('T')[0];
          idealMileageKm = dueMileageKm;
        } else if (timeDueDate < mileageDueDate) {
          triggerType = 'TIME';
          idealDate = dueDate;
          // Estimate mileage at time due date
          const daysToTimeDue = Math.ceil((timeDueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
          idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
        } else {
          triggerType = 'BOTH';
          idealDate = dueDate;
          idealMileageKm = dueMileageKm;
        }
      } else if (dueMileageKm !== null) {
        triggerType = 'MILEAGE';
        const dailyKm = await this.getAverageDailyKm(trainId);
        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
        idealDate = new Date(mileageDueDateMs).toISOString().split('T')[0];
        idealMileageKm = dueMileageKm;
      } else if (dueDate !== null) {
        triggerType = 'TIME';
        idealDate = dueDate;
        const dailyKm = await this.getAverageDailyKm(trainId);
        const daysToTimeDue = Math.ceil((new Date(dueDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
        idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
      }

      // Calculate compliance window dates
      const dailyKm = await this.getAverageDailyKm(trainId);
      let complianceStartDate = dateWindowStart ?? todayStr;
      let complianceEndDate = dateWindowEnd ?? todayStr;

      if (mileageWindowStart !== null) {
        const kmToStart = mileageWindowStart - currentMileageKm;
        const daysToStart = Math.max(0, Math.ceil(kmToStart / dailyKm));
        const startDateFromMileage = new Date(today);
        startDateFromMileage.setDate(startDateFromMileage.getDate() + daysToStart);

        if (!dateWindowStart || startDateFromMileage < new Date(dateWindowStart)) {
          complianceStartDate = startDateFromMileage.toISOString().split('T')[0];
        }
      }

      if (mileageWindowEnd !== null) {
        const kmToEnd = mileageWindowEnd - currentMileageKm;
        const daysToEnd = Math.ceil(kmToEnd / dailyKm);
        const endDateFromMileage = new Date(today);
        endDateFromMileage.setDate(endDateFromMileage.getDate() + daysToEnd);

        if (!dateWindowEnd || endDateFromMileage < new Date(dateWindowEnd)) {
          complianceEndDate = endDateFromMileage.toISOString().split('T')[0];
        }
      }

      // Ensure start date is not in the past
      if (complianceStartDate < todayStr) {
        complianceStartDate = todayStr;
      }

      // Check if overdue
      const isOverdue = complianceEndDate < todayStr;

      const result: PmDueResult = {
        pmTypeId,
        pmCode: pmType.pmCode,
        pmName: pmType.pmName,
        trainId,
        trainNumber: train.trainNumber,
        fleetId: train.fleetId,
        dueMileageKm,
        dueDate,
        currentMileageKm,
        kmUntilDue,
        daysUntilDue,
        triggerType,
        complianceWindow: {
          startDate: complianceStartDate,
          endDate: complianceEndDate,
          startMileageKm: mileageWindowStart,
          endMileageKm: mileageWindowEnd,
          idealDate,
          idealMileageKm,
        },
        isOverdue,
        lastPmDate,
        lastPmMileageKm,
      };

      span.setAttribute('pm.triggerType', triggerType);
      span.setAttribute('pm.isOverdue', isOverdue);
      span.setAttribute('pm.kmUntilDue', kmUntilDue ?? -1);

      return result;
    });
  }

  /**
   * Calculate PM due dates for all PM types for a train.
   */
  async calculateAllPmDue(trainId: string): Promise<PmDueResult[]> {
    return this.traced('calculateAllPmDue', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      // Get train with fleet
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      // Get all active PM types for this fleet
      const pmTypesList = await this.db.query.pmTypes.findMany({
        where: and(
          eq(pmTypes.fleetId, train.fleetId),
          eq(pmTypes.active, true)
        ),
        orderBy: [desc(pmTypes.intervalKm)],
      });

      const results: PmDueResult[] = [];

      for (const pmType of pmTypesList) {
        const dueResult = await this.calculateComplianceWindow(trainId, pmType.id);
        results.push(dueResult);
      }

      // Sort by due date (most urgent first)
      results.sort((a, b) => {
        const aDate = a.complianceWindow.idealDate;
        const bDate = b.complianceWindow.idealDate;
        return aDate.localeCompare(bDate);
      });

      span.setAttribute('result.pmCount', results.length);
      span.setAttribute('result.overdueCount', results.filter(r => r.isOverdue).length);

      return results;
    });
  }

  // ===========================================================================
  // PM Hierarchy Handling
  // ===========================================================================

  /**
   * Check if a higher-level PM has satisfied this PM type's requirement.
   *
   * PM Hierarchy: C4 satisfies C1/C2/C3, Overhaul satisfies all
   */
  private async checkHierarchySatisfaction(
    trainId: string,
    pmType: PmType,
    sinceDate: Date | null
  ): Promise<{ satisfiedBy: string | null; satisfiedByPm: PmScheduleRecord | null }> {
    // Find PM types that satisfy this one
    const satisfyingTypes = await this.db.query.pmTypes.findMany({
      where: and(
        eq(pmTypes.fleetId, pmType.fleetId),
        eq(pmTypes.active, true),
        sql`${pmType.pmCode} = ANY(${pmTypes.satisfiesCodes})`
      ),
    });

    if (satisfyingTypes.length === 0) {
      return { satisfiedBy: null, satisfiedByPm: null };
    }

    // Find the most recent completed PM of a satisfying type
    const satisfyingTypeIds = satisfyingTypes.map(t => t.id);
    const sinceDateFilter = sinceDate
      ? gte(pmSchedule.completedAt, sinceDate)
      : undefined;

    const satisfyingPm = await this.db.query.pmSchedule.findFirst({
      where: and(
        eq(pmSchedule.trainId, trainId),
        inArray(pmSchedule.pmTypeId, satisfyingTypeIds),
        eq(pmSchedule.status, 'COMPLETED'),
        isNull(pmSchedule.scenarioId),
        sinceDateFilter
      ),
      orderBy: desc(pmSchedule.completedAt),
    });

    if (satisfyingPm) {
      const satisfyingType = satisfyingTypes.find(t => t.id === satisfyingPm.pmTypeId);
      return {
        satisfiedBy: satisfyingType?.pmCode ?? null,
        satisfiedByPm: satisfyingPm,
      };
    }

    return { satisfiedBy: null, satisfiedByPm: null };
  }

  /**
   * Get PM types that this PM type satisfies (resets their counters).
   */
  async getSatisfiedPmTypes(pmTypeId: string): Promise<PmType[]> {
    return this.traced('getSatisfiedPmTypes', async (span) => {
      span.setAttribute('pm.typeId', pmTypeId);

      const pmType = await this.db.query.pmTypes.findFirst({
        where: eq(pmTypes.id, pmTypeId),
      });

      if (!pmType || !pmType.satisfiesCodes || pmType.satisfiesCodes.length === 0) {
        return [];
      }

      const satisfiedTypes = await this.db.query.pmTypes.findMany({
        where: and(
          eq(pmTypes.fleetId, pmType.fleetId),
          inArray(pmTypes.pmCode, pmType.satisfiesCodes),
          eq(pmTypes.active, true)
        ),
      });

      span.setAttribute('result.satisfiedCount', satisfiedTypes.length);
      return satisfiedTypes;
    });
  }

  // ===========================================================================
  // Track Allocation
  // ===========================================================================

  /**
   * Find suitable tracks for a PM based on type requirements.
   */
  async findSuitableTracks(
    pmTypeId: string,
    depotId: string | null,
    targetDate: string,
    durationDays: number
  ): Promise<TrackAllocation[]> {
    return this.traced('findSuitableTracks', async (span) => {
      span.setAttribute('pm.typeId', pmTypeId);
      span.setAttribute('pm.targetDate', targetDate);

      // Get PM type requirements
      const pmType = await this.db.query.pmTypes.findFirst({
        where: eq(pmTypes.id, pmTypeId),
      });

      if (!pmType) {
        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
          entityType: 'pm_type',
          entityId: pmTypeId,
        });
      }

      // Get required capabilities for this PM type
      const requiredCapabilities = await this.db.query.pmCapabilityRequirements.findMany({
        where: eq(pmCapabilityRequirements.pmTypeId, pmTypeId),
      });

      const mandatoryCapabilities = requiredCapabilities
        .filter(c => c.isMandatory)
        .map(c => c.capability);

      // Find tracks that match the track type
      const trackConditions: SQL<unknown>[] = [
        eq(tracks.trackType, pmType.trackType),
        eq(tracks.active, true),
      ];

      if (depotId) {
        trackConditions.push(eq(tracks.depotId, depotId));
      }

      const candidateTracks = await this.db.query.tracks.findMany({
        where: and(...trackConditions),
        with: {
          depot: true,
        },
      });

      // Check each track for capabilities and availability
      const allocations: TrackAllocation[] = [];
      const endDate = new Date(targetDate);
      endDate.setDate(endDate.getDate() + durationDays - 1);
      const endDateStr = endDate.toISOString().split('T')[0];

      for (const track of candidateTracks) {
        // Get track capabilities
        const capabilities = await this.db.query.trackCapabilities.findMany({
          where: and(
            eq(trackCapabilities.trackId, track.id),
            eq(trackCapabilities.isOperational, true)
          ),
        });

        const trackCapabilitySet = new Set(capabilities.map(c => c.capability));

        // Check mandatory capabilities
        const missingCapabilities = mandatoryCapabilities.filter(
          cap => !trackCapabilitySet.has(cap)
        );

        // Check availability (no conflicting PM)
        const conflicts = await this.db.query.pmSchedule.findMany({
          where: and(
            eq(pmSchedule.assignedTrackId, track.id),
            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
            isNull(pmSchedule.scenarioId),
            sql`${pmSchedule.targetDate} <= ${endDateStr}`,
            sql`DATE(${pmSchedule.targetDate}) + COALESCE(
              (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
            ) > ${targetDate}`
          ),
        });

        if (conflicts.length === 0) {
          allocations.push({
            trackId: track.id,
            trackNumber: track.trackNumber,
            depotId: track.depotId,
            depotCode: track.depot?.code ?? 'unknown',
            trackType: track.trackType as TrackType,
            startDate: targetDate,
            endDate: endDateStr,
            hasAllCapabilities: missingCapabilities.length === 0,
            missingCapabilities,
          });
        }
      }

      // Sort by capability match (prefer tracks with all capabilities)
      allocations.sort((a, b) => {
        if (a.hasAllCapabilities && !b.hasAllCapabilities) return -1;
        if (!a.hasAllCapabilities && b.hasAllCapabilities) return 1;
        return a.missingCapabilities.length - b.missingCapabilities.length;
      });

      span.setAttribute('result.trackCount', allocations.length);
      return allocations;
    });
  }

  /**
   * Check for track conflicts.
   */
  async checkTrackConflict(
    trackId: string,
    targetDate: string,
    durationDays: number,
    excludePmId?: string
  ): Promise<PmScheduleRecord | null> {
    return this.traced('checkTrackConflict', async (span) => {
      span.setAttribute('track.id', trackId);
      span.setAttribute('pm.targetDate', targetDate);

      const endDate = new Date(targetDate);
      endDate.setDate(endDate.getDate() + durationDays - 1);
      const endDateStr = endDate.toISOString().split('T')[0];

      const conditions: SQL<unknown>[] = [
        eq(pmSchedule.assignedTrackId, trackId),
        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
        isNull(pmSchedule.scenarioId),
        sql`${pmSchedule.targetDate} <= ${endDateStr}`,
        sql`DATE(${pmSchedule.targetDate}) + COALESCE(
          (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
        ) > ${targetDate}`,
      ];

      if (excludePmId) {
        conditions.push(sql`${pmSchedule.id} != ${excludePmId}`);
      }

      const conflict = await this.db.query.pmSchedule.findFirst({
        where: and(...conditions),
      });

      return conflict ?? null;
    });
  }

  // ===========================================================================
  // Material Constraint Checking
  // ===========================================================================

  /**
   * Check material availability for a PM.
   *
   * Material constraints:
   * - Hard (14 days): BLOCKING parts must be available
   * - Soft (90 days): Warning if parts unavailable
   */
  async checkMaterialAvailability(
    pmTypeId: string,
    depotId: string,
    targetDate: string
  ): Promise<MaterialConstraintResult> {
    return this.traced('checkMaterialAvailability', async (span) => {
      span.setAttribute('pm.typeId', pmTypeId);
      span.setAttribute('depot.id', depotId);
      span.setAttribute('pm.targetDate', targetDate);

      // Get required materials for this PM type
      const requirements = await this.db.query.pmMaterialRequirements.findMany({
        where: eq(pmMaterialRequirements.pmTypeId, pmTypeId),
      });

      if (requirements.length === 0) {
        return {
          isBlocked: false,
          hardConstraintViolations: [],
          softConstraintWarnings: [],
          totalMissingParts: 0,
          reservations: [],
        };
      }

      const today = new Date();
      const pmDate = new Date(targetDate);
      const daysUntilPm = Math.ceil((pmDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));

      const hardViolations: MaterialAvailability[] = [];
      const softWarnings: MaterialAvailability[] = [];
      const reservations: Array<{ partNumber: string; quantity: number; type: ReservationType }> = [];

      for (const req of requirements) {
        // Get inventory at the depot
        const inventory = await this.db.query.inventoryPositions.findFirst({
          where: and(
            eq(inventoryPositions.depotId, depotId),
            eq(inventoryPositions.partNumber, req.partNumber)
          ),
        });

        const availableQty = inventory
          ? (inventory.quantityOnHand ?? 0) - (inventory.quantityReserved ?? 0)
          : 0;

        const availability: MaterialAvailability = {
          partNumber: req.partNumber,
          partDescription: req.partDescription,
          criticality: req.criticality as MaterialCriticality,
          requiredQuantity: req.quantityPerPm,
          availableQuantity: availableQty,
          depotId,
          isAvailable: availableQty >= req.quantityPerPm,
          shortfall: Math.max(0, req.quantityPerPm - availableQty),
          leadTimeDays: req.leadTimeDays ?? 14,
          expectedAvailableDate: inventory?.nextDeliveryDate ?? null,
        };

        if (!availability.isAvailable) {
          // Check if this is a hard or soft constraint violation
          if (req.criticality === 'BLOCKING' && daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS) {
            hardViolations.push(availability);
          } else if (daysUntilPm <= SOFT_MATERIAL_WINDOW_DAYS) {
            softWarnings.push(availability);
          }
        }

        // Create reservation record
        if (availableQty >= req.quantityPerPm) {
          reservations.push({
            partNumber: req.partNumber,
            quantity: req.quantityPerPm,
            type: daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS ? 'HARD' : 'SOFT',
          });
        }
      }

      const isBlocked = hardViolations.length > 0;

      span.setAttribute('material.isBlocked', isBlocked);
      span.setAttribute('material.hardViolations', hardViolations.length);
      span.setAttribute('material.softWarnings', softWarnings.length);

      return {
        isBlocked,
        hardConstraintViolations: hardViolations,
        softConstraintWarnings: softWarnings,
        totalMissingParts: hardViolations.length + softWarnings.length,
        reservations,
      };
    });
  }

  // ===========================================================================
  // Maximo Lock Validation
  // ===========================================================================

  /**
   * Check if PM is locked by Maximo (INPRG work order).
   */
  async checkMaximoLock(pmScheduleId: string): Promise<{
    isLocked: boolean;
    workOrderId: string | null;
    maximoStatus: string | null;
    reason: string | null;
  }> {
    return this.traced('checkMaximoLock', async (span) => {
      span.setAttribute('pm.scheduleId', pmScheduleId);

      const pm = await this.db.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
      });

      if (!pm) {
        throw new PmScheduleNotFoundError(pmScheduleId);
      }

      // Check explicit lock
      if (pm.isLocked) {
        return {
          isLocked: true,
          workOrderId: pm.maximoWoId,
          maximoStatus: null,
          reason: pm.lockedReason ?? 'Manually locked',
        };
      }

      // Check Maximo work order status
      if (pm.maximoWoId) {
        // In a full implementation, we would query Maximo for status
        // For now, check if status is IN_PROGRESS
        if (pm.status === 'IN_PROGRESS') {
          return {
            isLocked: true,
            workOrderId: pm.maximoWoId,
            maximoStatus: 'INPRG',
            reason: 'Work order is in progress in Maximo',
          };
        }
      }

      return {
        isLocked: false,
        workOrderId: pm.maximoWoId,
        maximoStatus: null,
        reason: null,
      };
    });
  }

  // ===========================================================================
  // PM Scheduling Operations
  // ===========================================================================

  /**
   * Schedule a new PM.
   */
  async schedulePm(request: SchedulePmRequest): Promise<PmScheduleRecord> {
    return this.inTransaction('schedulePm', async (tx, span) => {
      const {
        trainId,
        pmTypeId,
        targetDate,
        assignedDepotId,
        assignedTrackId,
        assignedShift,
        notes,
        createdBy,
        skipMaterialCheck,
        skipServiceDemandCheck,
        skipLaborCapacityCheck,
      } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('pm.typeId', pmTypeId);
      span.setAttribute('pm.targetDate', targetDate);

      // Get train
      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
        with: { fleet: true, currentDepot: true },
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);

      // Get PM type
      const pmType = await tx.query.pmTypes.findFirst({
        where: eq(pmTypes.id, pmTypeId),
      });

      if (!pmType) {
        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
          entityType: 'pm_type',
          entityId: pmTypeId,
        });
      }

      // Calculate compliance window
      const dueResult = await this.calculateComplianceWindow(trainId, pmTypeId);

      // Validate target date is within compliance window
      if (targetDate < dueResult.complianceWindow.startDate ||
          targetDate > dueResult.complianceWindow.endDate) {
        throw new ComplianceWindowError(
          `Target date ${targetDate} is outside compliance window [${dueResult.complianceWindow.startDate}, ${dueResult.complianceWindow.endDate}]`,
          {
            windowStart: new Date(dueResult.complianceWindow.startDate),
            windowEnd: new Date(dueResult.complianceWindow.endDate),
            targetDate: new Date(targetDate),
          }
        );
      }

      // Check service demand (unless skipped)
      if (!skipServiceDemandCheck) {
        const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
          trainId,
          targetDate
        );

        if (!canSchedule) {
          throw new ServiceDemandViolationError(
            validation.message,
            {
              fleetId: validation.fleetId,
              requiredTrains: validation.required,
              availableTrains: validation.availableTrains,
            }
          );
        }
      }

      // Check unavailability
      const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(trainId);
      const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);

      if (blockingEvent) {
        throw new BusinessRuleError(
          `Train ${train.trainNumber} has active unavailability blocking PM scheduling: ${blockingEvent.eventType}`,
          {
            rule: 'unavailability_blocks_pm',
            context: { eventId: blockingEvent.id, eventType: blockingEvent.eventType },
          }
        );
      }

      // Determine depot
      const depotId = assignedDepotId ?? train.currentDepotId ?? train.homeDepotId;
      if (!depotId) {
        throw new ValidationError('No depot assigned and train has no current/home depot');
      }

      // Check labor capacity (unless skipped)
      // This validates that the depot has enough man-hours available for the target week
      let laborCapacityResult: LaborCapacityResult | null = null;
      if (!skipLaborCapacityCheck && pmType.estimatedHours) {
        const estimatedHours = parseFloat(pmType.estimatedHours);
        if (estimatedHours > 0) {
          laborCapacityResult = await this.manHourLevelingService.checkLaborCapacity(
            depotId,
            targetDate,
            estimatedHours
          );

          if (!laborCapacityResult.hasCapacity) {
            throw new LaborCapacityError(
              laborCapacityResult.message,
              {
                depotId,
                requiredHours: laborCapacityResult.totalRequiredHours,
                availableHours: laborCapacityResult.availableHours.total,
                utilizationPct: laborCapacityResult.utilizationPct,
                weekStart: laborCapacityResult.weekStart,
              }
            );
          }
        }
      }

      // Check material availability (unless skipped)
      let materialResult: MaterialConstraintResult | null = null;
      if (!skipMaterialCheck) {
        materialResult = await this.checkMaterialAvailability(pmTypeId, depotId, targetDate);

        if (materialResult.isBlocked) {
          const blockingParts = materialResult.hardConstraintViolations
            .map(v => v.partNumber)
            .join(', ');

          throw new MaterialConstraintError(
            `Blocking materials not available: ${blockingParts}`,
            {
              partNumber: materialResult.hardConstraintViolations[0]?.partNumber,
              requiredQuantity: materialResult.hardConstraintViolations[0]?.requiredQuantity,
              availableQuantity: materialResult.hardConstraintViolations[0]?.availableQuantity,
            }
          );
        }
      }

      // Find or validate track
      let trackId = assignedTrackId;
      if (!trackId) {
        const trackDuration = pmType.minTrackDays ?? 1;
        const suitableTracks = await this.findSuitableTracks(
          pmTypeId,
          depotId,
          targetDate,
          trackDuration
        );

        if (suitableTracks.length > 0) {
          trackId = suitableTracks[0].trackId;
        }
      } else {
        // Validate provided track
        const conflict = await this.checkTrackConflict(
          trackId,
          targetDate,
          pmType.minTrackDays ?? 1
        );

        if (conflict) {
          throw new TrackConflictError(
            `Track is already occupied on ${targetDate}`,
            {
              trackId,
              conflictingScheduleId: conflict.id,
            }
          );
        }
      }

      // Estimate mileage at target date
      const dailyKm = await this.getAverageDailyKm(trainId);
      const today = new Date();
      const daysUntilTarget = Math.ceil(
        (new Date(targetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
      );
      const targetMileageKm = (train.currentMileageKm ?? 0) + (daysUntilTarget * dailyKm);

      // Create PM schedule record
      const pmData: NewPmScheduleRecord = {
        trainId,
        pmTypeId,
        targetDate,
        targetMileageKm: Math.round(targetMileageKm),
        status: 'SCHEDULED',
        constraintStart: dueResult.complianceWindow.startDate,
        constraintEnd: dueResult.complianceWindow.endDate,
        assignedDepotId: depotId,
        assignedTrackId: trackId ?? null,
        assignedHours: pmType.estimatedHours,
        assignedShift: assignedShift ?? null,
        createdBy: createdBy ?? null,
      };

      const [created] = await tx.insert(pmSchedule).values(pmData).returning();
      span.setAttribute('pm.scheduleId', created.id);

      // Create audit history record
      if (createdBy) {
        const historyRecord: NewPmScheduleHistory = {
          pmScheduleId: created.id,
          changeType: 'CREATED',
          newTargetDate: targetDate,
          newStatus: 'SCHEDULED',
          newAssignedTrackId: trackId ?? null,
          newAssignedHours: pmType.estimatedHours,
          changedBy: createdBy,
          changeReason: notes ?? 'PM scheduled',
          changeSource: 'USER',
        };

        await tx.insert(pmScheduleHistory).values(historyRecord);
      }

      // Create material reservations
      if (materialResult?.reservations && materialResult.reservations.length > 0) {
        for (const reservation of materialResult.reservations) {
          const inventory = await tx.query.inventoryPositions.findFirst({
            where: and(
              eq(inventoryPositions.depotId, depotId),
              eq(inventoryPositions.partNumber, reservation.partNumber)
            ),
          });

          if (inventory) {
            await tx.insert(materialReservations).values({
              pmScheduleId: created.id,
              inventoryPositionId: inventory.id,
              partNumber: reservation.partNumber,
              quantityReserved: reservation.quantity,
              reservationType: reservation.type,
              reservedBy: createdBy ?? null,
              expiresAt: reservation.type === 'SOFT'
                ? new Date(Date.now() + 30 * 24 * 60 * 60 * 1000)
                : null,
            });

            // Update inventory reserved quantity
            await tx
              .update(inventoryPositions)
              .set({
                quantityReserved: sql`${inventoryPositions.quantityReserved} + ${reservation.quantity}`,
              })
              .where(eq(inventoryPositions.id, inventory.id));
          }
        }
      }

      this.log.info(
        {
          pmScheduleId: created.id,
          trainId,
          trainNumber: train.trainNumber,
          pmCode: pmType.pmCode,
          targetDate,
          trackId,
          depotId,
        },
        `PM scheduled: ${pmType.pmCode} for ${train.trainNumber} on ${targetDate}`
      );

      return created;
    });
  }

  /**
   * Move an existing PM to a new date.
   */
  async movePm(request: MovePmRequest): Promise<PmScheduleRecord> {
    return this.inTransaction('movePm', async (tx, span) => {
      const { pmScheduleId, newTargetDate, newTrackId, reason, movedBy } = request;

      span.setAttribute('pm.scheduleId', pmScheduleId);
      span.setAttribute('pm.newTargetDate', newTargetDate);

      // Get existing PM with relations
      const existingPm = await tx.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
        with: {
          train: true,
          pmType: true,
          assignedTrack: true,
        },
      }) as PmWithDetails | null;

      if (!existingPm) {
        throw new PmScheduleNotFoundError(pmScheduleId);
      }

      // Check Maximo lock
      const lockStatus = await this.checkMaximoLock(pmScheduleId);
      if (lockStatus.isLocked) {
        throw new MaximoLockError(
          `PM cannot be moved: ${lockStatus.reason}`,
          {
            workOrderId: lockStatus.workOrderId ?? undefined,
            maximoStatus: lockStatus.maximoStatus ?? undefined,
          }
        );
      }

      // Check status - only SCHEDULED can be moved
      if (existingPm.status !== 'SCHEDULED') {
        throw new BusinessRuleError(
          `PM cannot be moved: status is ${existingPm.status}`,
          {
            rule: 'pm_status_move',
            context: { currentStatus: existingPm.status },
          }
        );
      }

      // Validate new date is within compliance window
      if (newTargetDate < existingPm.constraintStart ||
          newTargetDate > existingPm.constraintEnd) {
        throw new ComplianceWindowError(
          `New target date ${newTargetDate} is outside compliance window [${existingPm.constraintStart}, ${existingPm.constraintEnd}]`,
          {
            windowStart: new Date(existingPm.constraintStart),
            windowEnd: new Date(existingPm.constraintEnd),
            targetDate: new Date(newTargetDate),
          }
        );
      }

      // Check service demand at new date
      const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
        existingPm.trainId,
        newTargetDate
      );

      if (!canSchedule) {
        throw new ServiceDemandViolationError(
          validation.message,
          {
            fleetId: validation.fleetId,
            requiredTrains: validation.required,
            availableTrains: validation.availableTrains,
          }
        );
      }

      // Handle track change
      let trackId = newTrackId ?? existingPm.assignedTrackId;
      if (trackId) {
        const conflict = await this.checkTrackConflict(
          trackId,
          newTargetDate,
          existingPm.pmType?.minTrackDays ?? 1,
          pmScheduleId
        );

        if (conflict) {
          // Try to find alternative track
          if (!newTrackId) {
            const alternatives = await this.findSuitableTracks(
              existingPm.pmTypeId,
              existingPm.assignedDepotId,
              newTargetDate,
              existingPm.pmType?.minTrackDays ?? 1
            );

            if (alternatives.length > 0) {
              trackId = alternatives[0].trackId;
            } else {
              trackId = null; // Clear track assignment
            }
          } else {
            throw new TrackConflictError(
              `Track is already occupied on ${newTargetDate}`,
              {
                trackId,
                conflictingScheduleId: conflict.id,
              }
            );
          }
        }
      }

      // Calculate new target mileage
      const dailyKm = await this.getAverageDailyKm(existingPm.trainId);
      const today = new Date();
      const daysUntilTarget = Math.ceil(
        (new Date(newTargetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
      );
      const currentMileage = existingPm.train?.currentMileageKm ?? 0;
      const newTargetMileageKm = currentMileage + (daysUntilTarget * dailyKm);

      // Record old values for history
      const oldTargetDate = existingPm.targetDate;
      const oldTrackId = existingPm.assignedTrackId;

      // Update PM schedule
      const [updated] = await tx
        .update(pmSchedule)
        .set({
          targetDate: newTargetDate,
          targetMileageKm: Math.round(newTargetMileageKm),
          assignedTrackId: trackId,
          updatedAt: new Date(),
        })
        .where(eq(pmSchedule.id, pmScheduleId))
        .returning();

      // Create audit history record
      const historyRecord: NewPmScheduleHistory = {
        pmScheduleId,
        changeType: 'DATE_CHANGED',
        oldTargetDate,
        newTargetDate,
        oldAssignedTrackId: oldTrackId,
        newAssignedTrackId: trackId,
        changedBy: movedBy,
        changeReason: reason,
        changeSource: 'USER',
      };

      await tx.insert(pmScheduleHistory).values(historyRecord);

      const trainNumber = existingPm.train?.trainNumber ?? 'unknown';
      const pmCode = existingPm.pmType?.pmCode ?? 'unknown';

      this.log.info(
        {
          pmScheduleId,
          trainNumber,
          pmCode,
          oldTargetDate,
          newTargetDate,
          reason,
          movedBy,
        },
        `PM moved: ${pmCode} for ${trainNumber} from ${oldTargetDate} to ${newTargetDate}`
      );

      return updated;
    });
  }

  /**
   * Lock a PM to prevent optimizer changes.
   */
  async lockPm(
    pmScheduleId: string,
    reason: string,
    lockedBy: string
  ): Promise<PmScheduleRecord> {
    return this.inTransaction('lockPm', async (tx, span) => {
      span.setAttribute('pm.scheduleId', pmScheduleId);

      const existing = await tx.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
      });

      if (!existing) {
        throw new PmScheduleNotFoundError(pmScheduleId);
      }

      if (existing.isLocked) {
        throw new BusinessRuleError('PM is already locked', {
          rule: 'pm_already_locked',
          context: { lockedBy: existing.lockedBy, lockedAt: existing.lockedAt },
        });
      }

      const [updated] = await tx
        .update(pmSchedule)
        .set({
          isLocked: true,
          lockedReason: reason,
          lockedBy,
          lockedAt: new Date(),
          updatedAt: new Date(),
        })
        .where(eq(pmSchedule.id, pmScheduleId))
        .returning();

      // Create audit history
      const historyRecord: NewPmScheduleHistory = {
        pmScheduleId,
        changeType: 'LOCKED',
        changedBy: lockedBy,
        changeReason: reason,
        changeSource: 'USER',
      };

      await tx.insert(pmScheduleHistory).values(historyRecord);

      this.log.info(
        { pmScheduleId, reason, lockedBy },
        `PM locked: ${pmScheduleId}`
      );

      return updated;
    });
  }

  /**
   * Unlock a PM to allow optimizer changes.
   */
  async unlockPm(pmScheduleId: string, unlockedBy: string): Promise<PmScheduleRecord> {
    return this.inTransaction('unlockPm', async (tx, span) => {
      span.setAttribute('pm.scheduleId', pmScheduleId);

      const existing = await tx.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
      });

      if (!existing) {
        throw new PmScheduleNotFoundError(pmScheduleId);
      }

      if (!existing.isLocked) {
        throw new BusinessRuleError('PM is not locked', {
          rule: 'pm_not_locked',
        });
      }

      // Cannot unlock if Maximo work order is in progress
      if (existing.maximoWoId && existing.status === 'IN_PROGRESS') {
        throw new MaximoLockError(
          'Cannot unlock PM with in-progress Maximo work order',
          {
            workOrderId: existing.maximoWoId,
            maximoStatus: 'INPRG',
          }
        );
      }

      const [updated] = await tx
        .update(pmSchedule)
        .set({
          isLocked: false,
          lockedReason: null,
          lockedBy: null,
          lockedAt: null,
          updatedAt: new Date(),
        })
        .where(eq(pmSchedule.id, pmScheduleId))
        .returning();

      // Create audit history
      const historyRecord: NewPmScheduleHistory = {
        pmScheduleId,
        changeType: 'UNLOCKED',
        changedBy: unlockedBy,
        changeReason: 'Manual unlock',
        changeSource: 'USER',
      };

      await tx.insert(pmScheduleHistory).values(historyRecord);

      this.log.info(
        { pmScheduleId, unlockedBy },
        `PM unlocked: ${pmScheduleId}`
      );

      return updated;
    });
  }

  // ===========================================================================
  // Tactical Scheduling Run
  // ===========================================================================

  /**
   * Run tactical scheduling for the 12-week horizon.
   *
   * This method:
   * 1. Calculates PM due dates for all trains in scope
   * 2. Prioritizes by overdue status and due date
   * 3. Attempts to schedule each PM respecting constraints
   * 4. Returns a detailed result with scheduled, deferred, and blocked PMs
   */
  async runTacticalSchedule(request: TacticalScheduleRequest): Promise<SchedulingResult> {
    return this.traced('runTacticalSchedule', async (span) => {
      const {
        fleetId,
        depotId,
        horizonWeeks = DEFAULT_HORIZON_WEEKS,
        dryRun = false,
        respectLocks = true,
      } = request;

      span.setAttribute('schedule.horizonWeeks', horizonWeeks);
      span.setAttribute('schedule.dryRun', dryRun);

      const today = new Date();
      const horizonStart = today.toISOString().split('T')[0];
      const horizonEnd = new Date(today.getTime() + horizonWeeks * 7 * 24 * 60 * 60 * 1000)
        .toISOString()
        .split('T')[0];

      // Get trains in scope
      const trainConditions: SQL<unknown>[] = [
        eq(trains.active, true),
        eq(trains.fitnessStatus, 'FIT'),
      ];

      if (fleetId) {
        trainConditions.push(eq(trains.fleetId, fleetId));
      }
      if (depotId) {
        trainConditions.push(eq(trains.currentDepotId, depotId));
      }

      const trainsInScope = await this.db.query.trains.findMany({
        where: and(...trainConditions),
        with: { fleet: true },
      });

      span.setAttribute('schedule.trainsInScope', trainsInScope.length);

      // Calculate PM due for all trains
      const allDueResults: PmDueResult[] = [];

      for (const train of trainsInScope) {
        const dueResults = await this.calculateAllPmDue(train.id);
        allDueResults.push(...dueResults);
      }

      // Filter to PMs due within horizon
      const pmsDueInHorizon = allDueResults.filter(pm =>
        pm.complianceWindow.startDate <= horizonEnd &&
        pm.complianceWindow.endDate >= horizonStart
      );

      // Sort by priority (overdue first, then by due date)
      pmsDueInHorizon.sort((a, b) => {
        if (a.isOverdue && !b.isOverdue) return -1;
        if (!a.isOverdue && b.isOverdue) return 1;
        return a.complianceWindow.idealDate.localeCompare(b.complianceWindow.idealDate);
      });

      span.setAttribute('schedule.pmsDueInHorizon', pmsDueInHorizon.length);

      // Process each PM
      const scheduled: SchedulingResultItem[] = [];
      const deferred: SchedulingResultItem[] = [];
      const blocked: SchedulingResultItem[] = [];
      const materialWarnings: SchedulingResult['materialWarnings'] = [];

      for (const pmDue of pmsDueInHorizon) {
        // Check if already scheduled
        const existingPm = await this.db.query.pmSchedule.findFirst({
          where: and(
            eq(pmSchedule.trainId, pmDue.trainId),
            eq(pmSchedule.pmTypeId, pmDue.pmTypeId),
            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
            isNull(pmSchedule.scenarioId),
            gte(pmSchedule.targetDate, horizonStart),
            lte(pmSchedule.targetDate, horizonEnd)
          ),
        });

        if (existingPm) {
          // Skip if locked and we're respecting locks
          if (respectLocks && existingPm.isLocked) {
            continue;
          }
        }

        // Try to schedule
        const result = await this.attemptSchedulePm(pmDue, horizonEnd, dryRun);

        if (result.status === 'SCHEDULED') {
          scheduled.push(result);

          if (result.materialConstraint?.softConstraintWarnings.length) {
            materialWarnings.push({
              trainId: pmDue.trainId,
              trainNumber: pmDue.trainNumber,
              pmCode: pmDue.pmCode,
              targetDate: result.targetDate!,
              warnings: result.materialConstraint.softConstraintWarnings,
            });
          }
        } else if (result.status === 'DEFERRED') {
          deferred.push(result);
        } else {
          blocked.push(result);
        }
      }

      // Calculate track utilization
      const trackUtilization = await this.calculateTrackUtilization(
        horizonStart,
        horizonEnd,
        depotId ?? null
      );

      const summary = {
        totalProcessed: pmsDueInHorizon.length,
        totalScheduled: scheduled.length,
        totalDeferred: deferred.length,
        totalBlocked: blocked.length,
        trackUtilizationPct: trackUtilization,
      };

      span.setAttribute('result.scheduled', scheduled.length);
      span.setAttribute('result.deferred', deferred.length);
      span.setAttribute('result.blocked', blocked.length);
      span.setAttribute('result.trackUtilization', trackUtilization);

      this.log.info(
        {
          horizonStart,
          horizonEnd,
          ...summary,
          fleetId,
          depotId,
        },
        `Tactical scheduling complete: ${scheduled.length} scheduled, ${deferred.length} deferred, ${blocked.length} blocked`
      );

      return {
        horizonStart,
        horizonEnd,
        scheduled,
        deferred,
        blocked,
        materialWarnings,
        summary,
      };
    });
  }

  /**
   * Attempt to schedule a single PM within constraints.
   */
  private async attemptSchedulePm(
    pmDue: PmDueResult,
    horizonEnd: string,
    dryRun: boolean
  ): Promise<SchedulingResultItem> {
    const explanation: SchedulingExplanation = {
      mileageTrigger: {
        intervalKm: null,
        currentMileageKm: pmDue.currentMileageKm,
        lastPmMileageKm: pmDue.lastPmMileageKm,
        kmSinceLastPm: pmDue.lastPmMileageKm !== null
          ? pmDue.currentMileageKm - pmDue.lastPmMileageKm
          : null,
        kmUntilDue: pmDue.kmUntilDue,
      },
      timeTrigger: {
        intervalMonths: null,
        lastPmDate: pmDue.lastPmDate,
        daysSinceLastPm: pmDue.lastPmDate
          ? Math.floor((Date.now() - new Date(pmDue.lastPmDate).getTime()) / (1000 * 60 * 60 * 24))
          : null,
        daysUntilDue: pmDue.daysUntilDue,
      },
      hierarchySatisfied: {
        satisfiedBy: null,
        satisfiedOnDate: null,
        counterResetFrom: null,
      },
      trackSelection: {
        candidateTracks: 0,
        selectedTrackId: null,
        selectionReason: '',
      },
      materialCheck: {
        totalParts: 0,
        availableParts: 0,
        blockedParts: 0,
        warningParts: 0,
      },
      laborCapacityCheck: {
        estimatedHours: 0,
        weeklyCapacity: 0,
        currentUtilization: 0,
        utilizationAfterScheduling: 0,
        hasCapacity: true,
      },
      constraints: [],
    };

    const warnings: string[] = [];

    // Check unavailability
    const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(pmDue.trainId);
    const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);

    if (blockingEvent) {
      explanation.constraints.push(`Blocked by unavailability: ${blockingEvent.eventType}`);

      return {
        trainId: pmDue.trainId,
        trainNumber: pmDue.trainNumber,
        pmTypeId: pmDue.pmTypeId,
        pmCode: pmDue.pmCode,
        status: 'BLOCKED',
        targetDate: null,
        targetMileageKm: null,
        trackAllocation: null,
        materialConstraint: null,
        laborCapacity: null,
        complianceWindow: pmDue.complianceWindow,
        deferralReason: `Train has active unavailability: ${blockingEvent.eventType}`,
        warnings,
        explanation,
      };
    }

    // Determine ideal target date (within horizon)
    let targetDate = pmDue.complianceWindow.idealDate;
    if (targetDate > horizonEnd) {
      targetDate = horizonEnd;
    }
    if (targetDate < new Date().toISOString().split('T')[0]) {
      targetDate = new Date().toISOString().split('T')[0];
    }

    // Check service demand
    const demandCheck = await this.serviceDemandService.canScheduleTrainForMaintenance(
      pmDue.trainId,
      targetDate
    );

    if (!demandCheck.canSchedule) {
      // Try alternative dates within compliance window
      const alternativeDate = await this.findAlternativeDateForServiceDemand(
        pmDue.trainId,
        pmDue.complianceWindow.startDate,
        pmDue.complianceWindow.endDate
      );

      if (!alternativeDate) {
        explanation.constraints.push(`Service demand violation: ${demandCheck.validation.message}`);

        return {
          trainId: pmDue.trainId,
          trainNumber: pmDue.trainNumber,
          pmTypeId: pmDue.pmTypeId,
          pmCode: pmDue.pmCode,
          status: 'DEFERRED',
          targetDate: null,
          targetMileageKm: null,
          trackAllocation: null,
          materialConstraint: null,
          laborCapacity: null,
          complianceWindow: pmDue.complianceWindow,
          deferralReason: demandCheck.validation.message,
          warnings,
          explanation,
        };
      }

      targetDate = alternativeDate;
      warnings.push(`Rescheduled to ${alternativeDate} due to service demand constraints`);
    }

    // Get train's depot
    const train = await this.db.query.trains.findFirst({
      where: eq(trains.id, pmDue.trainId),
    });

    const depotId = train?.currentDepotId ?? train?.homeDepotId;
    if (!depotId) {
      explanation.constraints.push('No depot available for train');

      return {
        trainId: pmDue.trainId,
        trainNumber: pmDue.trainNumber,
        pmTypeId: pmDue.pmTypeId,
        pmCode: pmDue.pmCode,
        status: 'BLOCKED',
        targetDate: null,
        targetMileageKm: null,
        trackAllocation: null,
        materialConstraint: null,
        laborCapacity: null,
        complianceWindow: pmDue.complianceWindow,
        deferralReason: 'Train has no assigned depot',
        warnings,
        explanation,
      };
    }

    // Get PM type for track duration
    const pmType = await this.db.query.pmTypes.findFirst({
      where: eq(pmTypes.id, pmDue.pmTypeId),
    });

    const trackDuration = pmType?.minTrackDays ?? 1;

    // Find suitable tracks
    const suitableTracks = await this.findSuitableTracks(
      pmDue.pmTypeId,
      depotId,
      targetDate,
      trackDuration
    );

    explanation.trackSelection.candidateTracks = suitableTracks.length;

    if (suitableTracks.length === 0) {
      explanation.constraints.push('No suitable tracks available');
      explanation.trackSelection.selectionReason = 'No tracks match requirements or all are occupied';

      return {
        trainId: pmDue.trainId,
        trainNumber: pmDue.trainNumber,
        pmTypeId: pmDue.pmTypeId,
        pmCode: pmDue.pmCode,
        status: 'DEFERRED',
        targetDate: null,
        targetMileageKm: null,
        trackAllocation: null,
        materialConstraint: null,
        laborCapacity: null,
        complianceWindow: pmDue.complianceWindow,
        deferralReason: 'No suitable tracks available',
        warnings,
        explanation,
      };
    }

    const selectedTrack = suitableTracks[0];
    explanation.trackSelection.selectedTrackId = selectedTrack.trackId;
    explanation.trackSelection.selectionReason = selectedTrack.hasAllCapabilities
      ? 'Track has all required capabilities'
      : `Track missing: ${selectedTrack.missingCapabilities.join(', ')}`;

    if (!selectedTrack.hasAllCapabilities) {
      warnings.push(`Selected track missing capabilities: ${selectedTrack.missingCapabilities.join(', ')}`);
    }

    // Check material availability
    const materialResult = await this.checkMaterialAvailability(
      pmDue.pmTypeId,
      depotId,
      targetDate
    );

    explanation.materialCheck.totalParts = materialResult.reservations.length +
      materialResult.hardConstraintViolations.length +
      materialResult.softConstraintWarnings.length;
    explanation.materialCheck.availableParts = materialResult.reservations.length;
    explanation.materialCheck.blockedParts = materialResult.hardConstraintViolations.length;
    explanation.materialCheck.warningParts = materialResult.softConstraintWarnings.length;

    if (materialResult.isBlocked) {
      const blockingParts = materialResult.hardConstraintViolations
        .map(v => v.partNumber)
        .join(', ');

      explanation.constraints.push(`Blocked by material constraint: ${blockingParts}`);

      return {
        trainId: pmDue.trainId,
        trainNumber: pmDue.trainNumber,
        pmTypeId: pmDue.pmTypeId,
        pmCode: pmDue.pmCode,
        status: 'BLOCKED',
        targetDate: null,
        targetMileageKm: null,
        trackAllocation: selectedTrack,
        materialConstraint: materialResult,
        laborCapacity: null,
        complianceWindow: pmDue.complianceWindow,
        deferralReason: `Blocking materials not available: ${blockingParts}`,
        warnings,
        explanation,
      };
    }

    if (materialResult.softConstraintWarnings.length > 0) {
      const warningParts = materialResult.softConstraintWarnings
        .map(w => w.partNumber)
        .join(', ');
      warnings.push(`Material warning: ${warningParts} may not be available`);
    }

    // Calculate target mileage
    const dailyKm = await this.getAverageDailyKm(pmDue.trainId);
    const daysUntilTarget = Math.ceil(
      (new Date(targetDate).getTime() - Date.now()) / (1000 * 60 * 60 * 24)
    );
    const targetMileageKm = pmDue.currentMileageKm + (daysUntilTarget * dailyKm);

    // Create the PM schedule if not dry run
    if (!dryRun) {
      try {
        await this.schedulePm({
          trainId: pmDue.trainId,
          pmTypeId: pmDue.pmTypeId,
          targetDate,
          assignedDepotId: depotId,
          assignedTrackId: selectedTrack.trackId,
          skipMaterialCheck: true, // Already checked
          skipServiceDemandCheck: true, // Already checked
        });
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        explanation.constraints.push(`Scheduling failed: ${errorMessage}`);

        return {
          trainId: pmDue.trainId,
          trainNumber: pmDue.trainNumber,
          pmTypeId: pmDue.pmTypeId,
          pmCode: pmDue.pmCode,
          status: 'BLOCKED',
          targetDate: null,
          targetMileageKm: null,
          trackAllocation: selectedTrack,
          materialConstraint: materialResult,
          laborCapacity: null,
          complianceWindow: pmDue.complianceWindow,
          deferralReason: errorMessage,
          warnings,
          explanation,
        };
      }
    }

    return {
      trainId: pmDue.trainId,
      trainNumber: pmDue.trainNumber,
      pmTypeId: pmDue.pmTypeId,
      pmCode: pmDue.pmCode,
      status: 'SCHEDULED',
      targetDate,
      targetMileageKm: Math.round(targetMileageKm),
      trackAllocation: selectedTrack,
      materialConstraint: materialResult,
      laborCapacity: null,
      complianceWindow: pmDue.complianceWindow,
      deferralReason: null,
      warnings,
      explanation,
    };
  }

  // ===========================================================================
  // Query Methods
  // ===========================================================================

  /**
   * Get PM schedule by ID with full details.
   */
  async getPm(pmScheduleId: string): Promise<PmWithDetails> {
    return this.traced('getPm', async (span) => {
      span.setAttribute('pm.scheduleId', pmScheduleId);

      const pm = await this.db.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
        with: {
          train: true,
          pmType: true,
          assignedTrack: true,
          assignedDepot: true,
        },
      });

      if (!pm) {
        throw new PmScheduleNotFoundError(pmScheduleId);
      }

      return pm as PmWithDetails;
    });
  }

  /**
   * Get PM history.
   */
  async getPmHistory(pmScheduleId: string) {
    return this.traced('getPmHistory', async (span) => {
      span.setAttribute('pm.scheduleId', pmScheduleId);

      const history = await this.db.query.pmScheduleHistory.findMany({
        where: eq(pmScheduleHistory.pmScheduleId, pmScheduleId),
        orderBy: desc(pmScheduleHistory.changedAt),
        with: {
          changedByUser: true,
        },
      });

      return history;
    });
  }

  // ===========================================================================
  // Helper Methods
  // ===========================================================================

  /**
   * Get last completed PM of a type for a train.
   */
  private async getLastCompletedPm(
    trainId: string,
    pmTypeId: string
  ): Promise<PmScheduleRecord | null> {
    const lastPm = await this.db.query.pmSchedule.findFirst({
      where: and(
        eq(pmSchedule.trainId, trainId),
        eq(pmSchedule.pmTypeId, pmTypeId),
        eq(pmSchedule.status, 'COMPLETED'),
        isNull(pmSchedule.scenarioId)
      ),
      orderBy: desc(pmSchedule.completedAt),
    });

    return lastPm ?? null;
  }

  /**
   * Get average daily km for a train from recent mileage readings.
   */
  private async getAverageDailyKm(trainId: string): Promise<number> {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const readings = await this.db
      .select({
        avgDailyKm: sql<number>`AVG(${mileageReadings.dailyKm})`,
      })
      .from(mileageReadings)
      .where(
        and(
          eq(mileageReadings.trainId, trainId),
          gte(mileageReadings.readingDate, thirtyDaysAgo.toISOString().split('T')[0]),
          eq(mileageReadings.validationStatus, 'VALID')
        )
      );

    return readings[0]?.avgDailyKm ?? DEFAULT_DAILY_KM;
  }

  /**
   * Find an alternative date for scheduling when service demand blocks the ideal date.
   */
  private async findAlternativeDateForServiceDemand(
    trainId: string,
    windowStart: string,
    windowEnd: string
  ): Promise<string | null> {
    const start = new Date(windowStart);
    const end = new Date(windowEnd);

    // Try each day in the window
    for (let d = start; d <= end; d.setDate(d.getDate() + 1)) {
      const dateStr = d.toISOString().split('T')[0];
      const { canSchedule } = await this.serviceDemandService.canScheduleTrainForMaintenance(
        trainId,
        dateStr
      );

      if (canSchedule) {
        return dateStr;
      }
    }

    return null;
  }

  /**
   * Calculate track utilization percentage for a period.
   */
  private async calculateTrackUtilization(
    startDate: string,
    endDate: string,
    depotId: string | null
  ): Promise<number> {
    // Get total track-days available
    const trackConditions: SQL<unknown>[] = [
      eq(tracks.active, true),
      sql`${tracks.trackType} != 'STABLING'`,
    ];

    if (depotId) {
      trackConditions.push(eq(tracks.depotId, depotId));
    }

    const trackCount = await this.db
      .select({ count: count() })
      .from(tracks)
      .where(and(...trackConditions));

    const totalTracks = trackCount[0]?.count ?? 0;
    const daysBetween = Math.ceil(
      (new Date(endDate).getTime() - new Date(startDate).getTime()) / (1000 * 60 * 60 * 24)
    );
    const totalTrackDays = totalTracks * daysBetween;

    if (totalTrackDays === 0) return 0;

    // Get scheduled PM track-days
    const pmConditions: SQL<unknown>[] = [
      inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
      isNull(pmSchedule.scenarioId),
      gte(pmSchedule.targetDate, startDate),
      lte(pmSchedule.targetDate, endDate),
      sql`${pmSchedule.assignedTrackId} IS NOT NULL`,
    ];

    if (depotId) {
      pmConditions.push(eq(pmSchedule.assignedDepotId, depotId));
    }

    const scheduledPms = await this.db.query.pmSchedule.findMany({
      where: and(...pmConditions),
      with: { pmType: true },
    });

    const usedTrackDays = scheduledPms.reduce((sum, pm) => {
      const duration = pm.pmType?.minTrackDays ?? 1;
      return sum + duration;
    }, 0);

    return Math.round((usedTrackDays / totalTrackDays) * 100);
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let pmSchedulerServiceInstance: PMSchedulerService | null = null;

export function getPMSchedulerService(): PMSchedulerService {
  if (!pmSchedulerServiceInstance) {
    pmSchedulerServiceInstance = new PMSchedulerService();
  }
  return pmSchedulerServiceInstance;
}

export default PMSchedulerService;

