     1→/**
     2→ * Drag Validation Utilities
     3→ *
     4→ * Helpers for validating PM drag-and-drop operations including:
     5→ * - Real-time constraint validation API calls
     6→ * - Debounced validation for performance
     7→ * - Impact assessment calculation
     8→ *
     9→ * @see specs/006-user-interface.md Section 6.3.4
    10→ */
    11→
    12→import type { DragValidationState, DragConstraintViolation, PmMoveImpact } from '../layers/types';
    13→
    14→// =============================================================================
    15→// Types
    16→// =============================================================================
    17→
    18→export interface ValidatePmMoveParams {
    19→  pmId: string;
    20→  currentDate: string;
    21→  targetDate: string;
    22→  trainId: string;
    23→}
    24→
    25→export interface ValidatePmMoveResponse {
    26→  isValid: boolean;
    27→  violations: DragConstraintViolation[];
    28→  impact?: PmMoveImpact;
    29→}
    30→
    31→// =============================================================================
    32→// Validation API
    33→// =============================================================================
    34→
    35→/**
    36→ * Validates a PM move against all constraints.
    37→ * Returns validation state including violations and impact assessment.
    38→ */
    39→export async function validatePmMove(
    40→  params: ValidatePmMoveParams,
    41→  options: { baseUrl?: string; signal?: AbortSignal } = {}
    42→): Promise<DragValidationState> {
    43→  const { baseUrl = '/api/v1', signal } = options;
    44→
    45→  try {
    46→    const response = await fetch(`${baseUrl}/pm/schedule/${params.pmId}/validate-move`, {
    47→      method: 'POST',
    48→      headers: {
    49→        'Content-Type': 'application/json',
    50→      },
    51→      body: JSON.stringify({
    52→        targetDate: params.targetDate,
    53→        trainId: params.trainId,
    54→      }),
    55→      signal,
    56→    });
    57→
    58→    if (!response.ok) {
    59→      // Handle specific error codes
    60→      if (response.status === 409) {
    61→        // Conflict - PM is locked in Maximo
    62→        return {
    63→          isValid: false,
    64→          message: 'PM is locked in Maximo (in progress)',
    65→          violations: [{
    66→            type: 'MAXIMO_LOCK',
    67→            severity: 'ERROR',
    68→            message: 'Cannot reschedule: PM is currently in progress in Maximo',
    69→          }],
    70→        };
    71→      }
    72→
    73→      throw new Error(`Validation failed: ${response.statusText}`);
    74→    }
    75→
    76→    const data = await response.json() as { data: ValidatePmMoveResponse };
    77→    const result = data.data;
    78→
    79→    return {
    80→      isValid: result.isValid,
    81→      message: result.violations.length > 0
    82→        ? result.violations.map(v => v.message).join('; ')
    83→        : null,
    84→      violations: result.violations,
    85→    };
    86→  } catch (error) {
    87→    // If request was aborted, return neutral state
    88→    if (error instanceof Error && error.name === 'AbortError') {
    89→      return {
    90→        isValid: true,
    91→        message: null,
    92→        violations: [],
    93→      };
    94→    }
    95→
    96→    // For network errors, return a warning (not blocking)
    97→    return {
    98→      isValid: true,
    99→      message: 'Unable to validate constraints (network error)',
   100→      violations: [{
   101→        type: 'SERVICE_DEMAND',
   102→        severity: 'WARNING',
   103→        message: 'Constraint validation unavailable - proceed with caution',
   104→      }],
   105→    };
   106→  }
   107→}
   108→
   109→/**
   110→ * Client-side quick validation for immediate feedback.
   111→ * Checks basic constraints without API call.
   112→ */
   113→export function quickValidatePmMove(
   114→  params: ValidatePmMoveParams & {
   115→    constraintStart: string;
   116→    constraintEnd: string;
   117→    isLocked: boolean;
   118→  }
   119→): DragValidationState {
   120→  const violations: DragConstraintViolation[] = [];
   121→
   122→  // Check if PM is locked
   123→  if (params.isLocked) {
   124→    violations.push({
   125→      type: 'MAXIMO_LOCK',
   126→      severity: 'ERROR',
   127→      message: 'Cannot move: PM is locked',
   128→    });
   129→  }
   130→
   131→  // Check compliance window
   132→  const targetDate = new Date(params.targetDate);
   133→  const windowStart = new Date(params.constraintStart);
   134→  const windowEnd = new Date(params.constraintEnd);
   135→
   136→  if (targetDate < windowStart) {
   137→    violations.push({
   138→      type: 'COMPLIANCE_WINDOW',
   139→      severity: 'ERROR',
   140→      message: `Target date ${params.targetDate} is before compliance window start (${params.constraintStart})`,
   141→    });
   142→  }
   143→
   144→  if (targetDate > windowEnd) {
   145→    violations.push({
   146→      type: 'COMPLIANCE_WINDOW',
   147→      severity: 'ERROR',
   148→      message: `Target date ${params.targetDate} is after compliance window end (${params.constraintEnd})`,
   149→    });
   150→  }
   151→
   152→  // Check if same date (no change)
   153→  if (params.currentDate === params.targetDate) {
   154→    return {
   155→      isValid: true,
   156→      message: null,
   157→      violations: [],
   158→    };
   159→  }
   160→
   161→  const hasErrors = violations.some(v => v.severity === 'ERROR');
   162→
   163→  return {
   164→    isValid: !hasErrors,
   165→    message: violations.length > 0
   166→      ? violations.map(v => v.message).join('; ')
   167→      : null,
   168→    violations,
   169→  };
   170→}
   171→
   172→// =============================================================================
   173→// Debounced Validation
   174→// =============================================================================
   175→
   176→interface DebouncedValidation {
   177→  validate: (params: ValidatePmMoveParams) => void;
   178→  cancel: () => void;
   179→}
   180→
   181→/**
   182→ * Creates a debounced validation function for real-time drag feedback.
   183→ * Cancels previous pending validation when a new position is provided.
   184→ */
   185→export function createDebouncedValidation(
   186→  onResult: (result: DragValidationState) => void,
   187→  options: { delay?: number; baseUrl?: string } = {}
   188→): DebouncedValidation {
   189→  const { delay = 150, baseUrl = '/api/v1' } = options;
   190→
   191→  let timeoutId: NodeJS.Timeout | null = null;
   192→  let abortController: AbortController | null = null;
   193→
   194→  const validate = (params: ValidatePmMoveParams) => {
   195→    // Cancel previous
   196→    if (timeoutId) {
   197→      clearTimeout(timeoutId);
   198→    }
   199→    if (abortController) {
   200→      abortController.abort();
   201→    }
   202→
   203→    // Create new abort controller
   204→    abortController = new AbortController();
   205→    const signal = abortController.signal;
   206→
   207→    // Schedule new validation
   208→    timeoutId = setTimeout(async () => {
   209→      const result = await validatePmMove(params, { baseUrl, signal });
